<section class="admin-page-head"><div><span class="eyebrow">Receipts and customer updates</span><h1>Email center</h1><p>Transactional receipts stay separate from consent-based marketing. Campaigns never send until an authorized person approves them.</p></div><form method="post" action="<?= url('admin/email/queue/run') ?>"><?= csrf_field() ?><button class="button button-primary" type="submit"><i data-lucide="send"></i>Process 25 queued</button></form></section>
<section class="customer-stat-grid"><article><span>Queued</span><strong><?= number_format((int)($counts['queued']??0)) ?></strong><i data-lucide="clock-3"></i></article><article><span>Sent</span><strong><?= number_format((int)($counts['sent']??0)) ?></strong><i data-lucide="mail-check"></i></article><article><span>Failed</span><strong><?= number_format((int)($counts['failed']??0)) ?></strong><i data-lucide="mail-warning"></i></article><article><span>Campaign ready</span><strong><?= $readiness['ready']?'Yes':'No' ?></strong><i data-lucide="shield-check"></i></article></section>
<?php if(!$readiness['ready']): ?><section class="admin-panel"><h2>Campaign safety gate</h2><p>Sending remains locked until all required settings are complete.</p><div class="detail-list"><?php foreach($readiness['checks'] as $key=>$ok): ?><div><dt><?= e(ucwords(str_replace('_',' ',$key))) ?></dt><dd><?= $ok?'Ready':'Needs attention' ?></dd></div><?php endforeach; ?></div><a class="button button-secondary" href="<?= url('admin/settings') ?>">Open settings</a></section><?php endif; ?>
<section class="admin-order-grid"><form method="post" action="<?= url('admin/email/campaigns') ?>" class="admin-panel"><?= csrf_field() ?><span class="eyebrow">Owner-approved only</span><h2>Draft a product update</h2><div class="form-grid"><label>Internal title<input name="title" required maxlength="120"></label><label>Email subject<input name="subject" required maxlength="140"></label><label class="full">Intro message<textarea name="intro_text" rows="4" required maxlength="1000"></textarea></label><fieldset class="full"><legend>Products</legend><div class="toggle-grid"><?php foreach($products as $product): ?><label class="check-row"><input type="checkbox" name="product_ids[]" value="<?= (int)$product['id'] ?>"><span><strong><?= e(trim($product['brand'].' '.$product['name'])) ?></strong><small>Added <?= e(date('M j, Y',strtotime($product['created_at']))) ?></small></span></label><?php endforeach; ?></div></fieldset></div><button class="button button-primary" type="submit">Save draft<i data-lucide="file-plus-2"></i></button></form>
<div class="admin-panel"><h2>Campaigns</h2><?php if(!$campaigns): ?><p>No campaigns yet.</p><?php endif; ?><?php foreach($campaigns as $campaign): ?><div class="receipt-items"><div><span><strong><?= e($campaign['title']) ?></strong><small><?= e(ucfirst($campaign['status'])) ?> · <?= (int)$campaign['recipient_count'] ?> recipients · <?= (int)$campaign['sent_count'] ?> sent</small></span><?php if($campaign['status']==='draft'): ?><span class="customer-export-actions"><form method="post" action="<?= url('admin/email/campaigns/'.$campaign['id'].'/approve') ?>"><?= csrf_field() ?><button class="button button-small button-primary" type="submit">Approve</button></form><form method="post" action="<?= url('admin/email/campaigns/'.$campaign['id'].'/cancel') ?>"><?= csrf_field() ?><button class="button button-small button-secondary" type="submit">Cancel</button></form></span><?php else: ?><b><?= (int)$campaign['failed_count'] ?> failed</b><?php endif; ?></div></div><?php endforeach; ?></div></section>
<section class="admin-panel"><h2>Recent delivery log</h2><div class="admin-table-wrap"><table class="admin-table"><thead><tr><th>Type</th><th>Recipient</th><th>Subject</th><th>Status</th><th>Created</th></tr></thead><tbody><?php foreach($queue as $email): ?><tr><td><?= e(ucwords(str_replace('_',' ',$email['message_type']))) ?></td><td><?= e($email['recipient_email']) ?></td><td><?= e($email['subject']) ?></td><td><span class="status-pill"><?= e(ucfirst($email['status'])) ?></span><?php if($email['last_error']): ?><small><?= e($email['last_error']) ?></small><?php endif; ?></td><td><?= e(date('M j · g:i A',strtotime($email['created_at']))) ?></td></tr><?php endforeach; ?></tbody></table></div></section>
